.darma-loader-uiverse-blue-ripple-rings {
  position: relative;
  width: 8em;
  height: 8em;
  display: flex;
  align-items: center;
  justify-content: center;
}

.darma-loader-uiverse-blue-ripple-rings::before,
.darma-loader-uiverse-blue-ripple-rings::after {
position: absolute;
box-sizing: border-box;
content: "";
height: 8em;
width: 8em;
border: 1em solid var(--loader-color, #0060fa);
border-radius: 50%;
animation: darma-loader-uiverse-blue-ripple-rings-loader_79178 2s linear infinite;
}

.darma-loader-uiverse-blue-ripple-rings::after {
opacity: 0;
animation-delay: 1s;
}

@keyframes darma-loader-uiverse-blue-ripple-rings-loader_79178 {
0% {
border: 1em solid var(--loader-color, #0060fa);
transform: scale(0);
opacity: 1;
}

100% {
border: 0 solid var(--loader-color, #0060fa);
transform: scale(1);
opacity: 0;
}
}

